const userMessage = $input.first().json.chatInput;
const sessionId = $input.first().json.sessionId || 'default-session';

return [{
  json: {
    sessionId,
    userMessage
  }
}];

// --- 1. Parser la sortie du LLM Extract ---
const llmOutput = $input.first().json;

let extracted = null;

// Cas 1 : le Basic LLM Chain retourne directement un objet JSON (quand format:json activé côté Ollama)
if (llmOutput && typeof llmOutput === 'object' && llmOutput.invoice_id !== undefined) {
  extracted = llmOutput;
}
// Cas 2 : le Basic LLM Chain retourne { text: "..." }
else if (llmOutput && typeof llmOutput.text === 'string') {
  try {
    let raw = llmOutput.text.trim();
    raw = raw.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').replace(/^```\s*/i, '');
    const firstBrace = raw.indexOf('{');
    const lastBrace = raw.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace !== -1) {
      raw = raw.substring(firstBrace, lastBrace + 1);
    }
    extracted = JSON.parse(raw);
  } catch (err) {
    extracted = { confidence: 0, needs_review: true, _parse_error: err.message };
  }
}

// Fallback si rien n'est exploitable
if (!extracted) {
  extracted = { confidence: 0, needs_review: true };
}

// --- 2. Récupérer le draft depuis PG Load Session et le userMessage ---
const pgSession = $('PG New Session').first().json;
const loadState = $('Load Session State').first().json;

const sessionId = pgSession.session_id;
const turn = pgSession.turn;
const draft = JSON.parse(JSON.stringify(pgSession.draft));

// Garantir la structure minimale du draft (si Postgres retourne un truc partiel)
draft.customer = draft.customer || {};
draft.product = draft.product || {};
draft.purchase = draft.purchase || {};
draft.issue = draft.issue || {};
draft.history = draft.history || [];
draft.missing_fields = draft.missing_fields || [];
draft.warnings = draft.warnings || [];
draft.status = draft.status || "draft";

// --- 3. Merge non-destructif ---
if (extracted.invoice_id && !draft.purchase.invoice_id) {
  draft.purchase.invoice_id = String(extracted.invoice_id);
}
if (extracted.product_type && !draft.product.category) {
  draft.product.category = extracted.product_type;
}
if (extracted.product_brand && !draft.product.brand) {
  draft.product.brand = extracted.product_brand;
}
if (extracted.issue_type && !draft.issue.type) {
  draft.issue.type = extracted.issue_type;
}
if (extracted.issue_description && !draft.issue.description) {
  draft.issue.description = extracted.issue_description;
}
if (extracted.customer_name && !draft.customer.name) {
  draft.customer.name = extracted.customer_name;
}
if (extracted.context && !draft.issue.context) {
  draft.issue.context = extracted.context;
}

// --- 4. Sortir le draft fusionné ---
return [{
  json: {
    sessionId,
    userMessage: loadState.userMessage,
    draft,
    extraction: extracted,
    intent: extracted?.intent || 'new_sav',
    turn
  }
}];

// Mock DB des factures
const invoicesDB = {
  "1234": {
    invoice_id: "1234",
    customer_id: "C-987",
    product_sku: "LL-BOSCH-WAG28400",
    date: "2024-03-15",
    store: "Magasin Bruxelles Centre",
    amount: 649.00,
    warranty_months: 24
  },
  "5678": {
    invoice_id: "5678",
    customer_id: "C-456",
    product_sku: "FRG-SAMSUNG-RB34",
    date: "2023-08-02",
    store: "Magasin Liège",
    amount: 899.00,
    warranty_months: 24
  },
  "9012": {
    invoice_id: "9012",
    customer_id: "C-987",
    product_sku: "TV-LG-OLED55",
    date: "2022-11-20",
    store: "Magasin Bruxelles Centre",
    amount: 1599.00,
    warranty_months: 24
  }
};

const input = $input.first().json;
const draft = JSON.parse(JSON.stringify(input.draft));
const invoiceId = draft.purchase.invoice_id;
const invoice = invoicesDB[invoiceId];

if (!invoice) {
  // Facture introuvable → warning mais on continue
  draft.warnings = draft.warnings || [];
  draft.warnings.push(`Facture ${invoiceId} introuvable en base`);
  return [{
    json: {
      ...input,
      draft,
      invoice_found: false
    }
  }];
}

// Calcul warranty_end
const purchaseDate = new Date(invoice.date);
const warrantyEnd = new Date(purchaseDate);
warrantyEnd.setMonth(warrantyEnd.getMonth() + invoice.warranty_months);

// Remplit le draft avec les infos de la facture (sans écraser)
draft.purchase.date = invoice.date;
draft.purchase.store = invoice.store;
draft.purchase.amount = invoice.amount;
draft.purchase.warranty_end = warrantyEnd.toISOString().split('T')[0];
draft.purchase.under_warranty = new Date() < warrantyEnd;

if (!draft.customer.id) draft.customer.id = invoice.customer_id;
if (!draft.product.sku) draft.product.sku = invoice.product_sku;

return [{
  json: {
    ...input,
    draft,
    invoice_found: true
  }
}];

// Mock DB clients
const customersDB = {
  "C-987": {
    id: "C-987",
    name: "Marie Dupont",
    email: "marie.dupont@example.com",
    phone: "+32 475 11 22 33",
    loyalty_tier: "gold",
    address: "Rue Neuve 12, 1000 Bruxelles"
  },
  "C-456": {
    id: "C-456",
    name: "Jean Martin",
    email: "j.martin@example.com",
    phone: "+32 478 44 55 66",
    loyalty_tier: "silver",
    address: "Quai de la Batte 8, 4000 Liège"
  }
};

const input = $input.first().json;
const draft = JSON.parse(JSON.stringify(input.draft));
const customerId = draft.customer.id;
const customer = customerId ? customersDB[customerId] : null;

if (customer) {
  // Merge : n'écrase pas les champs déjà renseignés par le conseiller
  draft.customer = {
    ...customer,
    ...draft.customer, // ce qui était déjà là garde la priorité
    id: customer.id    // sauf l'id qui vient de la facture
  };
}

return [{
  json: {
    ...input,
    draft,
    customer_found: !!customer
  }
}];

// Mock DB produits
const productsDB = {
  "LL-BOSCH-WAG28400": {
