    category: "television",
    brand: "LG",
    parts_available: false
  }
};

const input = $input.first().json;
const draft = JSON.parse(JSON.stringify(input.draft));
const sku = draft.product.sku;
const product = sku ? productsDB[sku] : null;

if (product) {
  draft.product = {
    ...product,
    ...draft.product, // priorité au conseiller
